WITH pi AS (SELECT id FROM _patient_ids WHERE idx=5), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2024-02-10','Primo-vaccination chiot — 1ère injection DHP + Lepto','Nala, femelle Beagle de 8 semaines, reçue pour primo-vaccination. La propriétaire rapporte un animal vif, joueur, bon appétit, selles normales. Pas d''antécédents.','Chiot en excellent état général. Poids 3,2 kg. T° 38,7°C, FC 130/min. Muqueuses rosées. Auscultation normale. Pas de parasites visibles. Ombilic cicatrisé.','Primo-vaccination réalisée : DHP (Nobivac DHPPi) + Leptospirose L4. 2e injection à prévoir dans 3–4 semaines. Conseils: vermifugation tous les 15 jours jusqu''à 2 mois, puis mensuelle jusqu''à 6 mois. Socialisation recommandée.','TERMINEE','## Ordonnance
**Nala** — Beagle femelle 8 sem. — 3,2 kg

- **Milbemax chiot** (milbémazole/praziquantel) : 1 comprimé le soir — renouveler dans 15 jours puis mensuellement jusqu''à 6 mois') RETURNING id) INSERT INTO _cons_ids SELECT 0, id FROM ins;
