WITH pi AS (SELECT id FROM _patient_ids WHERE idx=120), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-10-11','Paralysie postérieure brutale — IVDD aigu','Beagle femelle 6 ans (Paprika). Propriétaire: ne peut plus se lever depuis ce matin, cris de douleur lors du mouvement. Aucun antécédent neurologique. Chute ou choc non remarqué.','Paraplégie postérieure complète. Tonus anal diminué. Sensation douloureuse superficielle présente. Score neurologique: grade 3/5 IVDD (paraplégie sans perte nociception). Douleur vive rachis T12-L2. Réflexes patellaires exagérés (atteinte MNS).','IVDD Hansen type I T12-L2 probable. IRM rachidienne urgente: hernie discale T13-L1 compressive, écrasement moelle > 50%. Discussion chirurgie vs médical avec propriétaire. Chirurgie recommandée vu le grade neurologique (grade 3).','TERMINEE','Hospitalisation en cage stricte. Dexaméthasone 0,15 mg/kg IV dose unique. Gabapentine 5 mg/kg BID. Tramadol 5 mg/kg TID. Sondage vésical si rétention. Chirurgie programmée J+1.') RETURNING id) INSERT INTO _cons_ids SELECT 114, id FROM ins;
