WITH pi AS (SELECT id FROM _patient_ids WHERE idx=156), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-02-28','Luxation épaule — traumatisme','Chat européen mâle castré 4 ans (Axel). Déjà suivi pour plaie simple. Propriétaire: boiterie antérieure gauche soudaine après saut raté depuis armoire. Pas de plaie.','Membre antérieur G porté en abduction forcée, douleur vive manipulation épaule. Déformation palpable. Radiographie: luxation scapulo-humérale crânio-médiale. Pas de fracture associée.','Luxation épaule gauche pure. Réduction sous sédation (kétamine 5 mg/kg + diazépam 0,25 mg/kg IV). Réduction obtenue au 1er essai. Contrôle radio post-réduction: repositionnement correct. Écharpe + bandage Velpeau 10 jours.','TERMINEE','Méloxicam 0,05 mg/kg SID 7j. Bandage Velpeau 10 jours (rechange J5). Restriction activité 3 semaines. Contrôle radio J14.') RETURNING id) INSERT INTO _cons_ids SELECT 115, id FROM ins;
