WITH pi AS (SELECT id FROM _patient_ids WHERE idx=14), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-08-22','Vomissements répétés — suspicion CE gastrique','Perla, Yorkshire femelle 4 ans. Vomissements depuis 8h, total 6 épisodes. Propriétaire a retrouvé un jouet en plastique mâché incomplet. Appétit nul. Tentative de vomissement improductif.','Abdomen tendu, douloureux à la palpation gastrique. Nausée persistante. Radiographies: image radio-opaque gastrique 3x2 cm. Aucun corps étranger radio-transparent décelable sur clichés. Écho: masse hétérogène fundus gastrique.','CE gastrique bloqué (fragment jouet plastique). Endoscopie tentée — CE trop volumineux pour pince. Chirurgie gastrotomie nécessaire.','TERMINEE','Hospitalisation pré-op. Maropitant 1 mg/kg IV. Oméprazole 1 mg/kg IV. NPO stricte. Chirurgie gastrotomie dans 3h.') RETURNING id) INSERT INTO _cons_ids SELECT 116, id FROM ins;
