WITH pi AS (SELECT id FROM _patient_ids WHERE idx=5), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-12-26','Ingestion chocolat noir — intoxication théobromine','Nala, Labrador femelle 18 mois. Ingestion estimée 200g chocolat noir (pâtissier 70%) il y a 1h. Propriétaire a pesé la tablette restante. Quantité théobromine estimée: 450 mg (dose toxique 100-200 mg/kg). Poids Nala 28 kg.','Légère tachycardie 140/min. Pas encore de vomissements ni signes neurologiques. Muqueuses rosées, TRC normal. BU normale.','Intoxication théobromine: dose ingérée ~16 mg/kg (dose modérément toxique). Induction vomissement en urgence (apomorphine SC 0,04 mg/kg). Vomissements contenant résidus chocolat obtenus. Charbon activé administré. Monitoring cardiaque 4h.','TERMINEE','Charbon activé 1 g/kg dose unique (administré en clinique). Monitoring à domicile 24h (tachycardie, tremblements, vomissements). Revenir si symptômes. Pas d''alimentation 6h.') RETURNING id) INSERT INTO _cons_ids SELECT 117, id FROM ins;
