WITH pi AS (SELECT id FROM _patient_ids WHERE idx=175), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-01-15','Vomissements bilieux + prostration — obstruction intestinale','Faro, Berger Australien mâle 3 ans. Vomissements depuis 24h, aggravation progressive. Propriétaire: chien accès à poubelle cuisine il y a 36h (os de poulet). Abdomen distendu. Etat général se dégradant.','Douleur abdominale intense, position antalgique. T°39,8°C. Tachycardie 165/min. Déshydratation 7%. Radiographie: dilatation anses intestinales, image en "pile d''assiettes". Échographie: masse hyperéchogène iléon avec ombre acoustique.','Obstruction intestinale sur CE (os de poulet probable). Entérotomie d''urgence indiquée. Stabilisation hémodynamique: Ringer Lactate 20 mL/kg en 30 min puis 60 mL/kg/8h. Chirurgie dans 2h.','TERMINEE','Amoxicilline-clav 20 mg/kg IV. Métronidazole 15 mg/kg IV. Analgésie fentanyl. NPO. Chirurgie urgente.') RETURNING id) INSERT INTO _cons_ids SELECT 118, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=118),'SEED-0119',835,20,1002,'payée','2025-01-15','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=24), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-10-03','Ingestion raticide anticoagulant — intoxication bromadiolone','Coquine, Bichon femelle 3 ans. Propriétaire a trouvé boite de raticide bromadiolone mâchée dans le jardin. Ingestion survenue il y a 4h environ. Aucun symptôme actuel.','Animal cliniquement normal. T°38,5°C. Muqueuses rosées. TRC 2s. Pas d''hématome ni saignement visible. TP/TCA: normaux (les anticoagulants antagonistes vit K prennent 48-72h pour agir).','Intoxication bromadiolone (2ème génération, demi-vie longue). Induction vomissement (apomorphine SC). Traitement vitamine K1 préventif 30 jours. TP contrôle à J5 pour vérifier anticoagulation efficace.','TERMINEE','Vitamine K1 (Konakion) 5 mg/kg PO BID pendant 30 JOURS (durée importante bromadiolone). TP de contrôle à J5 et J35 (48h après arrêt vitamine K). Retourner en urgence si saignement, epistaxis, hématurie, abattement.') RETURNING id) INSERT INTO _cons_ids SELECT 119, id FROM ins;
