WITH pi AS (SELECT id FROM _patient_ids WHERE idx=43), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-02-09','Ingestion chewing-gum — suspicion xylitol','Diego, Beagle mâle castré 5 ans. Propriétaire a remarqué paquet de chewing-gum "sans sucre" à xylitol mâché (environ 10 dragées). Quantité xylitol estimée 1,5 g. Poids Diego 14 kg. Ingestion il y a 2h.','Animal légèrement apathique. Glycémie sur glucomètre: 3,2 mmol/L (hypoglycémie débutante). T°38,3°C. Muqueuses rosées.','Intoxication xylitol: dose ingérée ~107 mg/kg (seuil hépatotoxique: >500 mg/kg; seuil hypoglycémiant: >75 mg/kg). RISQUE hépatique et hypoglycémie. Induction vomissement. Hospitalisation surveillance glycémie 24h. Bilan hépatique J48h recommandé.','TERMINEE','Hospitalisation 24h monitoring glycémie. Glucosé 5% IV si glycémie <3 mmol/L. Bilan ALAT/ASAT à J2. Surveillance vomissements, ictère, troubles neurologiques.') RETURNING id) INSERT INTO _cons_ids SELECT 120, id FROM ins;
