WITH pi AS (SELECT id FROM _patient_ids WHERE idx=204), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-05','Ingestion plante — chat, suspicion intoxication lys','Chat européen femelle stérilisée 3 ans (Iris). Propriétaire confirme que le chat a mâché des feuilles de lys asiatique (Lilium sp.) dans un bouquet. Quantité indéterminée. Il y a 3h.','Hypersalivation, légère léthargie. Créatinine sérique (précoce): 130 µmol/L (limite supérieure). T°38,6°C. Urines: protéines +.','URGENCE ABSOLUE: intoxication lys chez le chat — toxicité rénale fulminante possible. Toute exposition doit être traitée comme une urgence. Emèse induite, charbon activé. Réhydratation IV massive 4 mL/kg/h 48h. Fonction rénale à surveiller en urgence.','TERMINEE','Hospitalisation OBLIGATOIRE 48-72h. NaCl 0,9% 4 mL/kg/h 48h. Créatinine + urée toutes 12h. Oméprazole IV. Si IRA: dialyse péritonéale envisagée.') RETURNING id) INSERT INTO _cons_ids SELECT 121, id FROM ins;
