WITH pi AS (SELECT id FROM _patient_ids WHERE idx=207), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-11-12','Vomissements + abattement — CE intestinal probable','Chat domestique mâle castré 2 ans (Lotus). Vomit depuis hier, mange une chaussette en coton selon propriétaire qui a trouvé morceau mâché. Clinique: abattement, anorexie.','Abdomen légèrement douloureux. Radiographies: pas de corps étranger radio-opaque. Échographie: contenu hyperéchogène avec ombre acoustique dans iléon (compatible CE textile).','CE textile (chaussette) dans intestin grêle. Pas de dilatation massive. Chirurgie d''entérotomie recommandée vu la nature du CE (non résorbable). Endoscopie insuffisante pour CE intestinal.','TERMINEE','NPO. Perfusion IV Ringer Lactate. Amoxicilline IV. Chirurgie programmée ce soir.') RETURNING id) INSERT INTO _cons_ids SELECT 122, id FROM ins;
