WITH pi AS (SELECT id FROM _patient_ids WHERE idx=135), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-04-18','Convulsions + hypersalivation — intoxication insecticide','Chien race mixte femelle 3 ans (Fauve). Propriétaire a appliqué pipette insecticide chien (perméthrine) sur un chat vivant dans le foyer. Le chat a pu lécher le chien. Le chat présente tremblements intenses.','Chat (et non le chien): tremblements musculaires violents, hypersalivation, mydriase. T°40,2°C (hyperthermie sur convulsions). Conscience altérée.','Intoxication à la perméthrine chez le CHAT (extrêmement sensible). Propriétaire a confondu: a appliqué pipette chien sur le chat. Risque vital. Bain savonneux immédiat, diazépam IV, refroidissement actif.','TERMINEE','Diazépam 0,5 mg/kg IV lent (anti-convulsivant). Bain eau tiède + savon doux immédiat. Méthocarbamol IV si tremblements persistants. Perfusion Ringer Lactate. Refroidissement si T > 40°C.') RETURNING id) INSERT INTO _cons_ids SELECT 123, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=123),'SEED-0124',280,20,336,'payée','2025-04-18','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=7), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2025-01-20','Pyodermite profonde étendue — WHWT atopique','Milou, WHWT mâle 6 ans, atopique connu sous Apoquel. Propriétaire signale lésions cutanées aggravées depuis 3 semaines malgré traitement. Furonculose faciale et dorsale visibles.','Furonculose étendue région inter-digitale, dorsale thoracique, faciale. Papules purulentes rompues, croûtes hémorragiques. Prurit intense malgré Apoquel. T°39,4°C. Ganglions rétromandibulaires tuméfiés. Cytologie: coques en grappes, neutrophiles.','Pyodermite profonde Staphylococcus pseudintermedius. Antibiothérapie systémique + locale. Culture + antibiogramme envoyé. Apoquel maintenu. Bains chlorhexidine 4% biquotidiens.','TERMINEE','En attente antibiogramme: Cefalexine 22 mg/kg BID 21j minimum. Apoquel 0,4 mg/kg SID maintenu. Bains Douxo S3 Pyo (chlorhexidine 3%) 2x/semaine. Cyclosporine envisagée si rechute.') RETURNING id) INSERT INTO _cons_ids SELECT 124, id FROM ins;
