WITH pi AS (SELECT id FROM _patient_ids WHERE idx=137), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2024-10-28','Abcès morsure — trajet fistuleux','Chien race mixte mâle 4 ans (Hector). Morsure par chien il y a 10 jours, plaie apparemment refermée. Maintenant: gonflement, chaleur locale, fistule spontanée avec jetage purulent.','Abcès fistulisé flanc gauche 6x4 cm, fluctuant. Trajet fistuleux sous-cutané profond palpable. T°39,9°C. Douleur intense. Pas de cellulite extensive.','Abcès sur morsure sous-estimée, fistulisé. Nécessite drainage chirurgical sous sédation, lavage H2O2 + sérum, pose mèche. Antibiothérapie systémique 3 semaines.','TERMINEE','Amoxicilline-clavulanate 22 mg/kg BID 21j. Méloxicam 0,2 mg/kg SID 7j. Soins locaux quotidiens (rinçage sérum + chlorhexidine). Rechange mèche J3. Contrôle J7.') RETURNING id) INSERT INTO _cons_ids SELECT 125, id FROM ins;
