WITH pi AS (SELECT id FROM _patient_ids WHERE idx=123), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2025-03-15','Pyodermite de surface étendue — Dalmatien','Sacha, Dalmatien femelle 3 ans. Lésions prurigineuses étendues depuis 3 semaines. Début par zone dorsale puis extension ventrale. Pas d''atopie connue. Pas de changement alimentaire.','Collerettes épidermiques multiples, pustules, croûtes sur dos, abdomen, face interne cuisses. Prurit modéré. T°38,7°C. Cytologie: coques intracellulaires. Pas de démodécie (raclage négatif).','Pyodermite de surface étendue (probablement post-virale ou immunomédiée chez Dalmatien). Culture: Staph pseudintermedius sensible cefalexine. Traitement systémique 4 semaines + shampooings.','TERMINEE','Cefalexine 22 mg/kg BID 28j. Shampoing Douxo S3 Pyo 2x/semaine. Méloxicam 0,1 mg/kg SID 5j (composante inflammatoire). Réévaluation J28. Bilan atopie si récidive.') RETURNING id) INSERT INTO _cons_ids SELECT 126, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=126),'SEED-0127',180,20,216,'payée','2025-03-15','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=115), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-12-10','Abcès sous-cutané profond — chat après morsure','Chat européen mâle entier 3 ans (Kiki). Propriétaire a trouvé le chat à l''extérieur avec gonflement important face latérale du cou. Morsure probable avec un autre chat (chat de voisin).','Abcès cervical gauche 4 cm de diamètre, fluctuant, très douloureux. T°40,1°C. Anorexie depuis 2 jours. Pas de plaie ouverte (membrane d''abcès intacte). Ganglions cervicaux tuméfiés.','Abcès morsure cervical chez chat entier. Fréquent. Incision + drainage sous sédation. Nécessite antibiothérapie. Test FIV/FeLV recommandé vu morsures à risque.','TERMINEE','Amoxicilline-clavulanate 12,5 mg/kg BID 14j. Méloxicam 0,05 mg/kg SID 5j. Soins locaux BID. Test FIV/FeLV J30. Castration recommandée pour réduire bagarres.') RETURNING id) INSERT INTO _cons_ids SELECT 127, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=127),'SEED-0128',170,20,204,'payée','2024-12-10','especes');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=176), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2025-02-03','Pyodermite récidivante — Labrador femelle','Gipsy, Labrador femelle 5 ans. 3ème épisode en 18 mois. Pyodermites récidivantes malgré plusieurs cures d''antibiotiques. Propriétaire découragé. Suspicion atopie sous-jacente non diagnostiquée.','Furonculose inter-digitale bilatérale, pustules ventrales, odeur de levure. T°38,6°C. Cytologie: coques + Malassezia. Bilan: NFS normale, hypothyroïdie à exclure (TSH normal). Test intradermal: positif acariens, graminées.','Pyodermite récidivante sur atopie sous-jacente. Plan: antibiothérapie court terme + contrôle facteur déclenchant (atopie). Traitement Apoquel + immunothérapie spécifique envisagée.','TERMINEE','Cefalexine 22 mg/kg BID 21j. Apoquel 0,4 mg/kg BID 14j puis SID. Ketoconazole 5 mg/kg SID 14j (Malassezia). Bain Malaseb 1x/semaine. Consultation immunothérapie spécifique proposée.') RETURNING id) INSERT INTO _cons_ids SELECT 128, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=128),'SEED-0129',310,20,372,'payée','2025-02-03','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=39), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-02-18','Bilan vision — cataracte bilatérale','Zeus, Golden Retriever mâle 9 ans. Propriétaire note difficultés à naviguer dans l''obscurité depuis 3 mois. Reflets bleutés dans les yeux visibles. Pas de douleur oculaire signalée.','Opacification cristallinienne bilatérale, stade mature OD / immature OG. Test ERG (électrorétinogramme): réponse rétinienne présente. PIO: 18 mmHg bilatéral (normal). Réflexe pupillaire présent.','Cataracte bilatérale sénile. OD: mature (opacité totale). OG: immature (75%). ERG positif = chirurgie de phacoémulsification envisageable avec bon pronostic visuel. Référence ophtalmologue vétérinaire spécialisé.','TERMINEE','Collyre Optimmune (cyclosporine 0,2%) OG BID pour ralentir progression immature. Antioxydants oraux (Vetri-DMG). Référence ophtalmologue spécialisé pour phacoémulsification OD.') RETURNING id) INSERT INTO _cons_ids SELECT 129, id FROM ins;
