WITH pi AS (SELECT id FROM _patient_ids WHERE idx=83), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2024-11-25','Conjonctivite chronique récidivante — chat','Choupette, Ragdoll femelle stérilisée 4 ans. Ecoulements oculaires bilatéraux séreux à muqueux depuis 2 mois. Déjà traité par collyre antibiotique sans succès complet.','Ecoulement muqueux bilatéral, hyperhémie conjonctivale. Fluorescéine: test négatif (pas d''ulcère). PIO: normale. Frottis conjonctival: corps d''inclusion à Chlamydophila. Test PCR Chlamydophila positif.','Chlamydophilose oculaire féline. Agent: Chlamydophila felis. Traitement systémique doxycycline + collyre. Prophylaxie autre chat du foyer si polyfoyer.','TERMINEE','Doxycycline 10 mg/kg SID PO 21 jours (systémique obligatoire). Collyre tétracycline 1% 3x/j 21j. Nettoyage yeux sérum physiologique matin. Contrôle J21.') RETURNING id) INSERT INTO _cons_ids SELECT 130, id FROM ins;
