WITH pi AS (SELECT id FROM _patient_ids WHERE idx=136), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-09','Ulcère cornéen — douleur oculaire aiguë','Gala, Labrador femelle 3 ans. Blépharospasme et épiphora oeil gauche depuis ce matin. Possible contact avec herbe haute hier. Oeil fermé, photophobie.','Blépharospasme intense OG. Fluorescéine: ulcère stromal profond 4mm diamètre, localisation centrale. Pas d''iris prolabé. PIO: 12 mmHg. Cytologie: coques — surinfection bactérienne. Menace de perforation si non traité.','Ulcère cornéen profond infecté. Risque perforation. Traitement intensif collyres antibiotiques + mydriatique + arrêt AINS systémiques. Collerette Elizabethan obligatoire.','TERMINEE','Collyre tobramycine 0,3% toutes 4h (6x/j) 14j. Collyre atropine 1% BID (mydriatique antispasmodique). Collyre sérum autologue 4x/j si disponible. AINS oraux CI. Collerette OBLIGATOIRE. Contrôle J3 urgent.') RETURNING id) INSERT INTO _cons_ids SELECT 131, id FROM ins;
