WITH pi AS (SELECT id FROM _patient_ids WHERE idx=12), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-09-30','Kératite pigmentaire — Carlin','Roxanne, Carlin femelle 4 ans. Propriétaire note voile brun progressif sur la cornée des deux yeux depuis 1 an. Pas de douleur apparente. Exposition cornéenne chronique secondaire à la conformation brachycéphale.','Pigmentation cornéenne nasal OD++, OG+. Kératite superficielle exposée. Larmoiement médial. Test Schirmer: 12 mm/min OD (limite basse). Entropion médial bilatéral léger. PIO: 15/14 mmHg.','Kératite pigmentaire brachycéphale sur entropion médial + syndrome KCS débutant. Traitement cyclosporine + lubrifiants. Discussion chirurgie entropion médial pour limiter progression.','TERMINEE','Optimmune collyre (cyclosporine 0,2%) BID à vie. Lubrifiants (Viscotears gel) TID. Contrôle Schirmer J60. Bilan chirurgie entropion médial proposé si < 10 mm/min.') RETURNING id) INSERT INTO _cons_ids SELECT 132, id FROM ins;
