WITH pi AS (SELECT id FROM _patient_ids WHERE idx=140), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-28','Traumatisme oculaire — AVP','Chat européen mâle 2 ans (Kos). AVP — retrouvé choqué. Oeil droit apparent anormal. Propriétaire paniqué.','Luxation du cristallin OD dans chambre antérieure. PIO OD: 42 mmHg (glaucome aigu secondaire). Hyphème chambr antérieure 30%. OG: intact. Autres blessures: plaie superficielle cuir chevelu. T°37,5°C (choc léger).','Traumatisme oculaire sévère: luxation cristallin OD + glaucome aigu + hyphème. Traitement médical urgence (réduire PIO) puis chirurgie lenticectomie si stabilisation. Pronostic visuel réservé OD.','TERMINEE','Dorzolamide-timolol collyre BID OD. Mannitol 20% 1 g/kg IV lent (hyperosmotique). Prednisone 1 mg/kg PO SID 7j. Anti-douleur systémique. Consultation ophtalmologie spécialisée urgente.') RETURNING id) INSERT INTO _cons_ids SELECT 133, id FROM ins;
