WITH pi AS (SELECT id FROM _patient_ids WHERE idx=26), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-10-16','Crise convulsive aiguë — Berger Belge','Sasha, Berger Belge mâle 4 ans, épileptique connu depuis 2 ans sous phénobarbital 2,5 mg/kg BID. Propriétaire: crise tonico-clonique généralisée durée 4 min au domicile il y a 30 min. Reprise de conscience depuis. 2ème crise ce mois.','Phase post-ictale: désorientation, ataxie, hypersalivation. T°39,8°C (hyperthermie post-crise). Phenobarbital sanguin (dosage): 18 µg/mL (sous-thérapeutique, cible 20-40). Hématologie + biochimie: normales.','Épilepsie idiopathique mal contrôlée: taux phénobarbital sous-thérapeutique. Ajustement dose. Addition bromure de potassium si nécessaire. Arrêt progressif possible si taux remontés OK.','TERMINEE','Phénobarbital AUGMENTÉ à 3 mg/kg BID. Dosage sanguin phénobarbital contrôle J21. Diazépam rectal (3 mg/kg, seringue préparée) à domicile — usage si crise > 5 min. Calendrier crises à tenir.') RETURNING id) INSERT INTO _cons_ids SELECT 134, id FROM ins;
