WITH pi AS (SELECT id FROM _patient_ids WHERE idx=26), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2025-01-16','Contrôle épilepsie — 3 mois post-ajustement','Sasha, Berger Belge 4 ans. Après augmentation phénobarbital en octobre. Propriétaire: 1 seule crise depuis (vs 3 avant). Dosage à renouveler. Toujours actif, appétit conservé.','Examen neurologique dans les limites de la normale. Pas de polyphagie excessive ni PU/PD. Phénobarbital sanguin: 28 µg/mL (zone thérapeutique). Bilirubine, ALAT, phosphatases alcalines: normaux.','Contrôle satisfaisant épilepsie. Taux phénobarbital thérapeutique. Hépatotoxicité surveillée (bilan hépatique normal). Maintien traitement actuel. Prochain bilan 6 mois.','TERMINEE','Phénobarbital 3 mg/kg BID maintenu. Bilan hépatique + dosage phénobarbital dans 6 mois. Diazépam rectal à domicile renouvelé.') RETURNING id) INSERT INTO _cons_ids SELECT 135, id FROM ins;
