WITH pi AS (SELECT id FROM _patient_ids WHERE idx=18), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-12-05','Paraplégie aiguë — Teckel IVDD','Cannelle, Teckel femelle 7 ans. Sautait du canapé ce matin — cri de douleur puis incapacité à se relever. Ne bouge plus les membres postérieurs. Déjà eu un épisode mineur il y a 3 ans traité médicalement.','Paraplégie complète. Tonus anal présent. Nociception superficielle: absente MP. Nociception profonde: douteuse. Grade IVDD: 4/5 (paraplégie + perte sensibilité superficielle). Douleur vive thoracolombaire.','IVDD Hansen type I grade 4/5 chez Teckel — urgence chirurgicale. IRM urgente T13-L1: hernie discale extrusive avec écrasement moelle 70%. Chirurgie hémilaminectomie dans les 12h. Pronostic réservé mais possible si nociception profonde présente.','TERMINEE','Cage rest strict. Analgésie: méthadone 0,3 mg/kg IV. Méthylprednisolone 30 mg/kg IV (protocole NASCIS controversé, discuté). Chirurgie urgente planifiée.') RETURNING id) INSERT INTO _cons_ids SELECT 136, id FROM ins;
