WITH pi AS (SELECT id FROM _patient_ids WHERE idx=120), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-25','Suivi post-IVDD — récupération neurologique','Paprika, Beagle femelle 6 ans. IVDD grade 3 traité chirurgicalement en octobre. Propriétaire: amélioration progressive mais démarche encore ataxique, quelques chutes.','Marche possible (grade 3→1 amélioré). Ataxie modérée membres postérieurs. Proprioception diminuée. Pas d''incontinence urinaire. Reprise pondérale +1 kg (surveiller obésité). Muscles paravertébraux légère atrophie.','Récupération neurologique satisfaisante à 3 mois post-hémilaminectomie. Kinésithérapie aquatique à poursuivre 3 mois. Gestion poids importante (obésité aggrave IVDD). Pronostic favorable.','TERMINEE','Gabapentine 5 mg/kg BID encore 4 semaines puis sevrage progressif. Physiothérapie aquatique (balnéothérapie) 2x/semaine 3 mois. Régime hypocalorique (Royal Canin Satiety). Contrôle J90.') RETURNING id) INSERT INTO _cons_ids SELECT 137, id FROM ins;
