WITH pi AS (SELECT id FROM _patient_ids WHERE idx=28), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2025-02-27','Détartrage sous AG — Golden Retriever','Caramel, Golden Retriever mâle 7 ans. Suivi dermato + gastro. Propriétaire signale forte halitose depuis 6 mois. Examen buccal en consultation: tartre grade 3 bilatéral, gingivite. Décision détartrage.','Tartre grade 3 canines et prémolaires. Gingivite modérée à sévère. 3 dents mobiles (104, 204, 309). T°38,5°C. Bilan pré-op: NFS + biochimie normaux. Cardio pré-op normal.','Détartrage sous AG avec radios dentaires et extractions si nécessaire. 3 dents mobiles → probable extraction.','TERMINEE','Antibiotiques pré et post-op: amoxicilline-clav 10j. Méloxicam 5j. Brossage dents quotidien dès J15. Dentisticks Virbac TID.') RETURNING id) INSERT INTO _cons_ids SELECT 145, id FROM ins;
