WITH pi AS (SELECT id FROM _patient_ids WHERE idx=31), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-10','Suivi lymphome — cycle 3 chimiothérapie CHOP','Axel, Boxeur mâle 7 ans, lymphome multicentrique stade III diagnostiqué en novembre. Protocole CHOP initié. Propriétaire: bonne tolérance cycles 1-2, légère fatigue post-vincristine. Ganglions en nette régression.','Lymphadénopathie considérablement réduite (sub-centimétrique). Poids stable 30 kg. Muqueuses rosées. NFS: neutrophiles 4,2 G/L (correct), plaquettes 185 G/L. Pas de signes digestifs.','Réponse complète au protocole CHOP — excellente. Cycle 3 administré (cyclophosphamide 250 mg/m2 IV + vincristine 0,5 mg/m2 IV). Rendez-vous cycle 4 dans 3 semaines. Pronostic favorable pour cette phase.','TERMINEE','Prednisone 2 mg/kg/j SID entre cycles. Oméprazole 1 mg/kg SID (gastroprotection). Surveillance quotidienne T°, appétit, selles. Urgence si T°<38 ou >39,5°C (neutropénie fébrile).') RETURNING id) INSERT INTO _cons_ids SELECT 146, id FROM ins;
