WITH pi AS (SELECT id FROM _patient_ids WHERE idx=31), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-08','Rechute lymphome post-rémission — Boxeur','Axel, Boxeur 7 ans. Rémission complète obtenue sous CHOP (6 cycles terminés en mars). Maintenant propriétaire note récidive ganglions axillaires depuis 10 jours. Abattement, anorexie.','Lymphadénomégalie axillaire bilatérale 3-4 cm. Ganglion poplité G tuméfié 2 cm. NFS: lymphocytose 18 G/L, blastes visibles sur frottis. Poids: -2 kg depuis dernier contrôle.','Rechute lymphome 5 semaines après fin CHOP. Médiane rémission chez Boxeur: 6-12 mois — ici rechute précoce (mauvais pronostic). Options: protocole sauvetage MOPP/LMPP ou soins palliatifs. Discussion approfondie propriétaire: choix soins palliatifs + qualité de vie.','TERMINEE','Protocole palliatif: Prednisone 40 mg/m2 SID (effet antiprolifératif + appétit). Chlorambucil 20 mg/m2 PO tous les 14j (tolérance). Contrôle mensuel. Soins de confort prioritaires.') RETURNING id) INSERT INTO _cons_ids SELECT 147, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=147),'SEED-0148',250,20,300,'payée','2025-04-08','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=48), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-10-17','Masse cutanée — mastocytome grade II','Bento, Bouledogue Anglais mâle 6 ans. Masse cutanée flanc gauche depuis 3 mois, légère croissance. Cytologie réalisée par vétérinaire référent: mastocytes nombreux, granules dégranulés. Référé pour exérèse + staging.','Masse dermique 3x2 cm, souple, bords mal définis. Prurit local. Pas d''érythème péri-lésionnel. Ganglion inguinal ipsilatéral légèrement tuméfié. Écho abdominale: rate homogène, pas d''adénopathie profonde. Grade histologique: II (Patnaik) ou Grade intermédiaire (Kiupel).','Mastocytome grade II — exérèse large (marges 2-3 cm) recommandée. Staging complet négatif. Pronostic intermédiaire. Discuter adjuvant (Palladia) si marges insuffisantes à l''histologie.','TERMINEE','Prednisone 1 mg/kg SID 10j pré-op (réduire risque dégranulation). Inhibiteurs H1 (loratadine) + H2 (famotidine) pré-op. Exérèse chirurgicale programmée.') RETURNING id) INSERT INTO _cons_ids SELECT 148, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=148),'SEED-0149',615,20,738,'payée','2024-10-17','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=201), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-02-26','Masse buccale ulcérée — mélanome oral stade III','Chien race mixte mâle 9 ans (Eden). Propriétaire note difficulté à manger, halitose intense depuis 2 mois. Masse noire ulcérée gencive mandibulaire gauche vue lors examen annuel.','Masse ulcérée 4x3 cm gencive mandibulaire gauche, fortement pigmentée, saignant au contact. Ganglion sous-mandibulaire G tuméfié 2 cm (métastase probable). Radiographie mandibulaire: ostéolyse mandibulaire sous-jacente. Scanner crâne: pas de méta cérébrale. Écho poumons: nodules sub-centimétriques suspects (méta douteuse).','Mélanome oral malin stade III (T3N1M0 possible). Pronostic sombre (médiane survie < 5 mois stade III). Options: exérèse + radiothérapie + vaccin mélanome canin (FDA approuvé USA). Discussion propriétaire: choix soins palliatifs + exérèse partielle pour confort.','TERMINEE','Méloxicam 0,2 mg/kg SID (anti-douleur + potentiel antitumoral). Alimentation humide, aliments mous. Réévaluation 1 mois. Référence oncologue vétérinaire pour discussion vaccin mélanome.') RETURNING id) INSERT INTO _cons_ids SELECT 149, id FROM ins;
