WITH pi AS (SELECT id FROM _patient_ids WHERE idx=160), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-22','Masse mammaire — carcinome mammaire chienne','Chienne Cocker Spaniel femelle entière 9 ans (Gala). Non stérilisée. Propriétaire découvre masse 2 cm cinquième mamelle droite lors toilettage. Aucun signe systémique.','Masse 5ème mamelle droite: 2,5 cm, ferme, bords mal définis, légèrement adhérente. Ganglion inguinal D: légère tuméfaction. Chaîne mammaire gauche: petite masse 1 cm 3ème mamelle. Écho abdominale: ganglions iliaques modérément augmentés. Radio thorax: pas de méta pulmonaire.','Carcinome mammaire probable (cytologie = carcinome tubulaire). Exérèse en bloc chaîne mammaire droite + OVH concomitante recommandée. Chaîne gauche: exérèse séparée ou surveillance.','TERMINEE','Chirurgie mastectomie régionale + OVH planifiée. Bilan pré-op complet. Antibioprophylaxie peri-op.') RETURNING id) INSERT INTO _cons_ids SELECT 150, id FROM ins;
