WITH pi AS (SELECT id FROM _patient_ids WHERE idx=33), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-11-20','Boiterie sévère — masse radius — ostéosarcome suspect','Chien race mixte grande taille mâle 8 ans (Nino). Boiterie sévère membre antérieur droit progressive depuis 6 semaines. Non améliorée sous AINS. Propriétaire: gonflement visible autour du radius distal.','Gonflement distal radius D: masse ferme, douloureuse, chaude. Radiographie: lyse osseuse agressive radius distal avec réaction périostée "en feu d''artifice". Lésion pathognomonique ostéosarcome. Méta pulmonaires: nodules 3mm (3 nodules, méta précoces).','Ostéosarcome appendiculaire stade II (méta pulmonaires micrométriques). Pronostic réservé: médiane survie sans traitement 1-3 mois, avec amputation + chimio: 12-18 mois. Options: amputation membre + carboplatine IV x4, ou traitement palliatif.','TERMINEE','Analgésie palliative: Méloxicam 0,2 mg/kg + Gabapentine 5 mg/kg BID + Tramadol. Discussion amputation + chimio adjuvante avec propriétaire. Décision: accepté après réflexion.') RETURNING id) INSERT INTO _cons_ids SELECT 151, id FROM ins;
