WITH pi AS (SELECT id FROM _patient_ids WHERE idx=91), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-02-05','Détresse respiratoire — lymphome médiastinal félin','Chat européen mâle castré 4 ans (Merlin). Dyspnée progressive depuis 3 semaines. Propriétaire: chat ouverture de bouche lors d''efforts. Abattement, anorexie depuis 5 jours. Âge jeune inhabituel.','Détresse respiratoire modérée (FR 48/min). Matité ventrale thorax bilatérale. Discordance thoracique. Radio thorax: masse médiastinale crâniale volumineuse + épanchement pleural bilatéral. FIV/FeLV: négatifs. Cytologie épanchement: lymphoblastes nombreux.','Lymphome médiastinal T de haut grade chez jeune chat. FeLV négatif. Pronostic réservé (médiane 2-4 mois avec chimio). Thoracocentèse urgente pour soulagement. Protocole COP (cyclophosphamide + vincristine + prednisone) discuté.','TERMINEE','Thoracocentèse urgente (400 mL retirés). Prednisone 2 mg/kg SID. Chimiothérapie COP démarrée J3. Oxygénothérapie si détresse. Pronostic discuté propriétaire.') RETURNING id) INSERT INTO _cons_ids SELECT 152, id FROM ins;
