WITH pi AS (SELECT id FROM _patient_ids WHERE idx=128), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-03-18','Ulcère buccal chronique — carcinome squameux félin','Chat Persan mâle castré 11 ans (Obi). Propriétaire: difficultés à manger progressives depuis 2 mois, ptyalisme, perte de poids 800g. Ulcère buccal vu par toiletteur.','Ulcère nécrotique gencive mandibulaire G 2 cm, rosettes blanchâtres. Ptyalisme sanglinolent. Poids 3,8 kg (perte 800g). Ostéolyse mandibulaire sur radio. Ganglion sub-mandibulaire G 1,5 cm. Biopsie: carcinome squameux bien différencié.','Carcinome épidermoïde buccal félin stade III. Pronostic sombre (médiane < 2 mois). Discussion honnête avec propriétaire: chirurgie impossible (envahissement osseux), RT = accès difficile. Soins palliatifs pris en charge.','TERMINEE','Méloxicam 0,05 mg/kg SID. Buprenorphine transdermique 0,02 mg/kg BID. Alimentation liquide par seringue ou sonde si nécessaire. Consultation soins palliatifs proposée.') RETURNING id) INSERT INTO _cons_ids SELECT 153, id FROM ins;
