WITH pi AS (SELECT id FROM _patient_ids WHERE idx=3), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-10-29','GDV — dilatation-torsion gastrique urgence vitale','Chien Dogue Allemand mâle 5 ans (Brutus). Propriétaire: ballonnement abdominal brutal après repas, tentatives vomissements improductives depuis 2h. Décubitus impossible, très agité.','État de choc: muqueuses grises, TRC 4s, FC 160/min, TA 70/40. Abdomen distendu, tympanique. Radiographie debout latérale: estomac dilaté compartimentalisé "double bulle" (signe GDV). Glasgow Coma Score 15 (alerte).','GDV confirmé — urgence chirurgicale absolue. Mortalité sans chirurgie 100%. Réanimation en parallèle: cathéter jugulaire, Ringer Lactate 90 mL/kg/h 30min, décompression par sonde oro-gastrique tentée (partiellement possible). Chirurgie dans 30 minutes.','TERMINEE','Hospitalisation soins intensifs post-opératoire. Réanimation IV. ECG continu (arythmies ventriculaires fréquentes post-GDV).') RETURNING id) INSERT INTO _cons_ids SELECT 154, id FROM ins;
