WITH pi AS (SELECT id FROM _patient_ids WHERE idx=64), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-01-30','Pyomètre fermé — chienne non stérilisée','Loky, Border Collie femelle entière 6 ans. Propriétaire: abattement, polydipsie intense depuis 5 jours. Chaleurs terminées il y a 6 semaines. Pas d''écoulement vulvaire. Ventre arrondi.','Déshydratation 8%. Tachycardie 140/min. Abdomen pendulaire. Écho: utérus très dilaté, cornes 4-5 cm diamètre, contenu liquidien échogène. Leucocytose 35 G/L avec déviation gauche. Urée 18 mmol/L (azotémie pré-rénale). T°40,3°C.','Pyomètre fermé — urgence chirurgicale. Risque rupture utérine + péritonite. Réanimation puis OVH d''urgence dans 2h.','TERMINEE','Réanimation IV NaCl 0,9% 20 mL/kg/h. Amoxicilline-clav 20 mg/kg IV. Métronidazole 15 mg/kg IV. OVH urgence dans 2h.') RETURNING id) INSERT INTO _cons_ids SELECT 155, id FROM ins;
