WITH pi AS (SELECT id FROM _patient_ids WHERE idx=30), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-09-11','Jetage vulvaire purulent — pyomètre ouvert','Chienne Setter Irlandais femelle entière 5 ans (Amber). Écoulement vulvaire verdâtre abondant depuis 3 jours. Chaleurs il y a 5 semaines. Légère polydipsie. Appétit diminué.','Écoulement purulent vulvaire vert-jaunâtre. Abdomen légèrement douloureux. Écho: utérus dilaté cornes 3cm. Leucocytose 22 G/L. T°39,5°C. Fonction rénale normale.','Pyomètre ouvert (col ouvert). Moins urgent que pyomètre fermé mais chirurgie recommandée. Réanimation légère puis OVH dans 12h. Traitement médical prostaglandines NON recommandé (chienne désirée pour reproduction? — non, propriétaire opte pour stérilisation).','TERMINEE','OVH programmée J+1. Amoxicilline-clav IV. Perfusion modérée NaCl.') RETURNING id) INSERT INTO _cons_ids SELECT 156, id FROM ins;
