WITH pi AS (SELECT id FROM _patient_ids WHERE idx=74), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-04-14','Délivrance difficile — dystocie chatte','Grizou, Maine Coon femelle entière 4 ans. En travail depuis 4h. 2 chatons nés normalement. Arrêt travail depuis 2h — chaton visible à la vulve mais pas expulsé. Épuisement maternel.','Chaton en présentation antérieure, tête engagée. Contractions inefficaces. FC mère 180/min. Muqueuses normales. Écho utérus: 2 fœtus encore in utero, mobiles. Glycémie mère: 4,2 mmol/L (basse par effort).','Dystocie par inertie utérine secondaire. Ocytocine IV tentée (5 UI dilué): extraction 3ème chaton réussie 15 min. 4ème chaton: extraction manuelle douce. Césarienne évitée.','TERMINEE','Glucosé 5% SC 20 mL si faiblesse. Surveillance chatons (tétée dans 2h). Retour si chaton supplémentaire non expulsé dans 2h. Ovariectomie recommandée après sevrage.') RETURNING id) INSERT INTO _cons_ids SELECT 157, id FROM ins;
