WITH pi AS (SELECT id FROM _patient_ids WHERE idx=97), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-12-18','Chatte post-partum — métrite aiguë','Chat Européen femelle 2 ans (Fantôme). Mise bas il y a 5 jours, 4 chatons. Depuis hier: écoulement vulvaire malodorant brun-verdâtre, fièvre, refus allaitement.','T°40,8°C. Jetage vaginal purulent abondant. Utérus légèrement douloureux. Leucocytose 28 G/L. NFS: neutrophiles toxiques. Écho utérus: reliquats placentaires + contenu liquidien (métrite sub-aiguë).','Métrite aiguë post-partum sur rétention placentaire. Antibiotiques IV urgents + traitement utérotonique. Chatons: alimentation artificielle (lait maternisé) pendant traitement mère.','TERMINEE','Amoxicilline-clav 22 mg/kg BID 14j. Cabergoline (Galastop) 5 µg/kg SID 5j (taris lactation si traitements incompatibles allaitement). Méloxicam 3j. Perfusion NaCl. Contrôle J5.') RETURNING id) INSERT INTO _cons_ids SELECT 158, id FROM ins;
