WITH pi AS (SELECT id FROM _patient_ids WHERE idx=171), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-06','Rupture vésicale traumatique — AVP chien','Chien Berger Belge femelle 3 ans (Dana). AVP avec voiture. Animal apporté en urgence. Prostré, ne peut pas uriner depuis l''accident.','Choc hypovolémique: muqueuses blanches, FC 160/min, TA 65/40. Abdomen douloureux, liquide abdominal palpable. Écho FAST: ascite abondante. Cystocentèse abdominale: urine (ratio créatinine abdominale/sérique > 2). K+ sérique 7,5 mmol/L.','Rupture vésicale traumatique + uroabdomen + hyperkaliémie sévère. Double urgence: réanimation anti-choc + correction hyperkaliémie + chirurgie. Sondage rétrograde vésical (réduction fuites). Cystorraphie dans 4h.','TERMINEE','NaCl 0,9% 90 mL/kg/h. Gluconate Ca 0,5 mL/kg IV (hyperkaliémie). Bicarbonate si acidose. Sondage rétrograde. Cystorraphie urgente.') RETURNING id) INSERT INTO _cons_ids SELECT 159, id FROM ins;
