WITH pi AS (SELECT id FROM _patient_ids WHERE idx=9), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-02-18','Décompensation ICC — CMD Dobermann stade C','Thor, Dobermann mâle 8 ans, CMD B2 connu sous Vetmedin + Fortekor depuis 18 mois. Propriétaire: aggravation brutale depuis 3 jours: dyspnée repos, toux nocturne, abattement. Oedèmes membres antérieurs.','Détresse respiratoire modérée: FR 48/min, posture orthopnéique. Auscultation: crépitants bilatéraux + 3ème bruit. FC 145/min, arythmie. TA 85/55. Radio thorax: oedème pulmonaire grade 3, cardiomégalie massive. Echocardiographie: FE 18% (effondrement), DP VG +35%.','Décompensation ICC CMD stade C. Urgence thérapeutique. Furosémide IV bolus + CRI. Dobutamine CRI si non réponse. Ajustement Vetmedin + Fortekor. Restriction sodée stricte.','TERMINEE','Furosémide 4 mg/kg IV bolus puis 1 mg/kg/h CRI. Pimobendan augmenté à 0,3 mg/kg BID. Enalapril 0,5 mg/kg BID (si TA > 90). Restriction hydrique et sodée. Monitoring quotidien FR, poids.') RETURNING id) INSERT INTO _cons_ids SELECT 160, id FROM ins;
