WITH pi AS (SELECT id FROM _patient_ids WHERE idx=20), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-01','IM stade C — ascite + détresse — Cavalier','Lola, Cavalier King Charles femelle 9 ans. Insuffisance mitrale stade B2 contrôlée. Décompensation brutale: ventre distendu depuis 2 jours, toux sèche, dyspnée légère. 4ème épisode en 2 ans.','Ascite modérée à sévère (vague abdominale +). Crépitants pulmonaires bilatéraux légers. FC 130/min, arythmie. Echo: régurgitation mitrale massive, dilatation OG/VG sévère, épanchement péricardique minime, ascite. TA 105/70.','IM stade C avec ascite sur épanchement abdominal. Furosémide IV + spironolactone (anti-aldostérone). Abdominocentèse si gène respiratoire.','TERMINEE','Furosémide bolus 4 mg/kg IV puis 2 mg/kg PO BID. Spironolactone 2 mg/kg BID ajoutée. Pimobendan 0,25 mg/kg BID maintenu. Benazépril 0,5 mg/kg SID. Pesée quotidienne. Urgence si prise de poids > 500g/48h.') RETURNING id) INSERT INTO _cons_ids SELECT 161, id FROM ins;
