WITH pi AS (SELECT id FROM _patient_ids WHERE idx=200), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-03-12','CMD Golden — progression B1→B2 confirmée','Eden, Golden Retriever femelle 8 ans. CMD B1 diagnostiquée en 2024. Echo de contrôle annuel. Propriétaire: légère toux nocturne depuis 1 mois, activité réduite.','Auscultation: galop proto-diastolique. FC 100/min. Echo: dilatation VG progressive (LVIDDN 1,75). ESVI augmenté. FE: 32% (vs 42% l''an dernier). Atrium gauche/Aorte: 1,6. Pas d''oedème pulmonaire radiographique.','CMD Golden passage B1→B2 (critères EPIC remplis: LVIDDN > 1,7, ACM/Ao > 1,6). Initiation pimobendan selon recommandations EPIC. Enregistrement Holter ECG 24h recommandé.','TERMINEE','Vetmedin (pimobendan) 0,25 mg/kg BID INITIATION. Benazépril 0,5 mg/kg SID. Monitoring mensuel FR repos. Contrôle écho 6 mois. Holter ECG commandé.') RETURNING id) INSERT INTO _cons_ids SELECT 162, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=162),'SEED-0163',315,20,378,'payée','2025-03-12','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=16), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-28','IM stade B2 — initiation pimobendan — Yorkshire','Princesse, Yorkshire femelle 11 ans. IM B1 depuis 2 ans sous bénazépril seul. Echo de contrôle: critères EPIC atteints (OG/Ao > 1,7, dilatation VG). Passage stade B2 confirmé.','Souffle systolique 5/6. Echo: OG/Ao 1,75. LVIDDN 1,72. FE 48% (limite). Pas d''oedème pulmonaire. TA 110/75. Poids 3,2 kg.','MMVD stade B2 — indication pimobendan selon guidelines ACVIM 2019. Ajout Vetmedin. Maintien benazepril. Contrôle écho 6 mois.','TERMINEE','Vetmedin 1,25 mg PO BID (demi-comprimé) 1h avant repas. Benazépril 5 mg SID maintenu. Radio thorax mensuelle à domicile (FR repos < 30/min). Urgence si FR > 35/min.') RETURNING id) INSERT INTO _cons_ids SELECT 163, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=163),'SEED-0164',230,20,276,'payée','2025-01-28','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=127), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-16','CMH stade C — OAP félin','Woody, Maine Coon mâle 7 ans. CMH B2 connu sous atenolol. Propriétaire appelle: chat respire bouche ouverte, cyanose labiale légère. Urgence.','Détresse respiratoire sévère: FR 68/min, respiration abdominale, cyanose. O2 immédiat (chambre). Radio thorax: OAP massif bilatéral. Épanchement pleural bilatéral modéré. Echo CMH: épaisseur septum 9mm, SAM+.','OAP aigu sur CMH stade C — urgence absolue. Thoracocentèse immédiate + furosémide IV. Gêner le moins possible (stress = mort). Pas d''examen prolongé.','TERMINEE','Furosémide 4 mg/kg IV x2 30 min. Clopidogrel 18,75 mg SID maintenu. Atenolol 6,25 mg BID (réduit à SID — FC trop lente). Ramipril 0,125 mg/kg SID ajouté. O2 continu 12h.') RETURNING id) INSERT INTO _cons_ids SELECT 164, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=164),'SEED-0165',475,20,570,'payée','2025-04-16','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=119), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-02-10','Anorexie prolongée — lipidose hépatique chat','Chat Européen femelle stérilisée 6 ans (Mina). Anorexie totale depuis 10 jours suite à déménagement. Propriétaire tardé à consulter. Ictère visible depuis 2 jours.','Ictère cutanéo-muqueux, déshydratation 10%. Poids 3,2 kg (-1,8 kg en 10 jours). ALAT 580 UI/L, bilirubine totale 85 µmol/L. Echo foie: hyperéchogène diffuse (aspect lipidose). Phosphatases 420 UI/L. Albumine basse 19 g/L.','Lipidose hépatique féline (Hepatic Lipidosis Syndrome) — secondaire au jeûne. Urgence nutritionnelle. Sonde naso-oesophagienne (SNO) ou oesophagostomie pour alimentation forcée. Pronostic: 60-80% si pris en charge rapidement.','TERMINEE','Pose sonde oesophagostomie (OT) sous AG court. Alimentation Hill''s a/d 40 kcal/kg/j via sonde x4/j. SAM-e 90 mg/j (hépatoprotecteur). Vitamine B12 250 µg SC hebdo. Antiémétique maropitant SID. Contrôle bilirubine J7.') RETURNING id) INSERT INTO _cons_ids SELECT 165, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=165),'SEED-0166',618,20,741.6,'payée','2025-02-10','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=145), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-11-28','Retard croissance + ictère — shunt porto-systémique','Yorkshire Terrier femelle 8 mois (Bijou). Propriétaire: chiot toujours plus petit que ses congénères, crises de désorientation post-prandiales, ictère intermittent. NFS et biochimie: ALAT 180, ammoniac élevé 145 µmol/L (N<50).','Naine, poids 1,2 kg (devrait être 2,5 kg). Léger ictère. Episodes hépato-encéphalopathie post-prandiale. Écho foie: petit (microhepatie). Scintigraphie hépatique portale: shunt porto-cave extrahépatique confirmé.','Shunt porto-systémique congénital extrahépatique — Yorkshire prédisposé. Chirurgie atténuateur (banding graduel ou ameroid constrictor) recommandée. Stabilisation médicale préalable.','TERMINEE','Lactulose 0,5 mL/kg TID PO (réduction ammoniac). Alimentation Royal Canin Hepatic (restriction protéique modérée). Metronidazole 7,5 mg/kg BID (réduction flore ammonigène). Chirurgie atténuateur programmée.') RETURNING id) INSERT INTO _cons_ids SELECT 166, id FROM ins;
