WITH pi AS (SELECT id FROM _patient_ids WHERE idx=41), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-09-25','Cétoacidose diabétique — Labrador','Bruno, Labrador mâle 8 ans, DM insulino-dépendant connu. Propriétaire en vacances, a oublié insuline 4 jours. Chien trouvé prostate, vomissements, haleine acétonée.','Prostration, déshydratation 10-12%. pH sanguin 7,15 (acidose métabolique). Cétones urinaires +++. Glycémie 34 mmol/L. K+ 3,2 mmol/L (hypokaliémie). Créatinine 140 µmol/L. T°37,1°C.','Cétoacidose diabétique sévère. Protocole CAD: NaCl 0,9% réanimation, insuline régulière CRI (0,1 UI/kg/h), corrections K+, monitoring glycémie horaire, bicarbonate si pH < 7,1.','TERMINEE','Hospitalisation soins intensifs. Insuline régulière CRI (Actrapid). Ringer Lactate + KCl. Bicarbonatémie monitoring. Passage insuline longue durée (Caninsulin) dès glycémie < 14 mmol/L et alimentation reprise.') RETURNING id) INSERT INTO _cons_ids SELECT 167, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=167),'SEED-0168',685,20,822,'payée','2024-09-25','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=130), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-01-14','Pancréatite nécrosante sévère — Schnauzer','Astro, Schnauzer mâle castré 6 ans (antécédent pancréatite 2024). Repas de fête (graisses) il y a 24h. Vomissements en jets répétés, douleur abdominale intense, effondrement état général.','Position de prière antalgique. T°40,4°C. Douleur épigastrique intense. Déshydratation 10%. Lipase pancréatique (Spec cPL): 3400 UI/L (VN < 200). Écho: pancréas hypéchogène entouré de liquide hypoéchogène péri-pancréatique, nécrose partielle.','Pancréatite nécrosante sévère. Prise en charge aggressive: réanimation IV, NPO, analgésie multimodale, anti-émétiques, support nutritionnel par sonde si > 48h.','TERMINEE','Hospitalisation soins intensifs. Ringer Lactate 5 mL/kg/h. Butorphanol 0,4 mg/kg IV TID + ketamine CRI 10 µg/kg/min. Maropitant IV SID. NPO 48h puis alimentation par sonde si non reprise.') RETURNING id) INSERT INTO _cons_ids SELECT 168, id FROM ins;
