WITH pi AS (SELECT id FROM _patient_ids WHERE idx=85), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-25','Ictère sévère + prostration — insuffisance hépatique aiguë','Stella, chat Européen femelle stérilisée 6 ans (déjà vue pour FIC). Ictère apparu brutalement en 5 jours. Anorexie. Propriétaire: pas de médicaments récents, pas de plantes toxiques connues.','Ictère cutanéo-muqueux sévère. Déshydratation 8%. ALAT 1850 UI/L, bilirubine 180 µmol/L. Temps de coagulation allongé: TP 40%. GGT 340. Écho: hépatite diffuse, pas de cholélithiase. Biopsie: hépatite lymphocytaire.','Insuffisance hépatique aiguë fulminante. Cause: hépatite lymphocytaire immune probable. Traitement: SAM-e + ursodiol + prednisone (si origine immune). Nutrition assistée. Vitamine K injectable.','TERMINEE','SAM-e 90 mg SID (hépatoprotecteur). Ursodiol 15 mg/kg SID. Prednisone 1 mg/kg SID 4 semaines. Vitamine K1 5 mg SC une dose. Sonde OT alimentation si anorexie persistante. Bilan hépatique J14.') RETURNING id) INSERT INTO _cons_ids SELECT 169, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=169),'SEED-0170',575,20,690,'payée','2025-03-25','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=55), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-12-09','Polyuro-polydipsie + prise de poids — suspicion Cushing','Chien Caniche mâle castré 9 ans (Max). PU/PD intense depuis 4 mois. Ventre pendulaire progressif. Alopécie symétrique bilatérale flancs. Polyorexie. Plusieurs infections cutanées dans l''année.','Prise de poids +3 kg. Abdomen pendulaire (dépôt graisseux abdominal). Alopécie flancs bilatérale symétrique non prurigineuse. Foie augmenté de taille (hépatomégalie). ACTH-stim test: cortisol post-ACTH 850 nmol/L (N<550). Écho surrénales: bilatéralement augmentées.','Hyperadrénocorticisme (maladie de Cushing) hypophyso-dépendant confirmé. Traitement trilostane. Bilan ophtalmologique (calcinose cutanée, HTA).','TERMINEE','Vétoryl (trilostane) 2 mg/kg SID PO à débuter. Test ACTH-stim contrôle à J10 (cible: cortisol 50-150 nmol/L post-ACTH). Contrôle électrolytes + biochimie J10. Urgence si abattement brutal (crise addisonnienne iatrogène).') RETURNING id) INSERT INTO _cons_ids SELECT 170, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=170),'SEED-0171',418,20,501.6,'payée','2024-12-09','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=21), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-07','Cushing + hypothyroïdie simultanés — Bullmastiff','Hercule, Bullmastiff mâle castré 8 ans, hypothyroïdie connue sous Levothyrox vétérinaire. Propriétaire: malgré traitement thyroïdien, PU/PD et ventre pendulaire réapparus. Alopécie étendue.','TSH normal, T4 libre normal (traitement thyroïdien efficace). ACTH-stim test: cortisol 780 nmol/L — HAC confirmé CONCURRENT. Biochimie: ALAT 650 (hépatoMégalie Cushing). Dexaméthasone faibles doses: freinables (HAC hypophysaire).','Concurrence hypothyroïdie traitée + HAC nouvellement diagnostiqué. Ajout trilostane. Prudence: les deux traitements peuvent nécessiter ajustements réciproques.','TERMINEE','Vétoryl 2 mg/kg SID ajouté. Levothyrox maintenu même dose. Contrôle ACTH-stim J10. Contrôle T4 libre J30 (Cushing modifie besoins thyroïdiens).') RETURNING id) INSERT INTO _cons_ids SELECT 171, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=171),'SEED-0172',360,20,432,'payée','2025-01-07','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=155), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-03','Prostration soudaine — crise addisonnienne','Chat européen mâle 5 ans (Nox). Propriétaire: animal trouvé prostré ce matin, incapable de se lever. Pas d''antécédent connu. Épisode de stress intense la veille (déménagement).','État de choc: FC 100/min (bradycardie), TA 60/30, muqueuses blanches. K+ 7,8 mmol/L, Na+ 118 mmol/L (ratio Na/K < 27: pathognomonique Addison). Cortisol basale: 10 nmol/L (NF > 55). ECG: ondes T ampleuses (hyperkaliémie sévère).','Crise addisonnienne (insuffisance surrénalienne aiguë). Urgence vitale. Réanimation anti-choc, correction hyperkaliémie, glucocorticoïdes IV.','TERMINEE','NaCl 0,9% 20-40 mL/kg/h IV urgence. Dexaméthasone 0,1 mg/kg IV (GC rapide). Gluconate Ca 0,5 mL/kg IV si ESV (K+ 7,8). Desoxycortone (DOCP) une fois stabilisé. Prednisone maintenance à vie.') RETURNING id) INSERT INTO _cons_ids SELECT 172, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=172),'SEED-0173',440,20,528,'payée','2025-03-03','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=94), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-07','Triade féline — hyperthyroïdie + IRC + CMH','Tom, Européen mâle castré 14 ans. Hyperthyroïdie traitée Felimazole 2,5 mg BID depuis 1 an, IRC stade 2 connue. Propriétaire: CMH diagnostiquée sur écho de contrôle. Gestion complexe des 3 pathologies simultanées.','Poids 3,8 kg stable. T4 libre: 42 pmol/L (légèrement élevé — dose Felimazole insuffisante). Créatinine 230 µmol/L (IRC stade 2 stable). Echo: CMH légère (septum 5,5mm, fonction systolique conservée). TA 165/110 (HTA — cible < 160).','Triade féline — équilibre délicat. Augmenter Felimazole risque d''aggraver IRC (hyperthyroïdie masque IRC). Traitement HTA: amlodipine. CMH légère: surveiller. Approche multidisciplinaire.','TERMINEE','Felimazole 2,5 mg BID maintenu (augmentation prudente 3,75 mg BID si T4 stable). Amlodipine 0,625 mg SID (HTA). Clopidogrel 18,75 mg SID (prévention thrombus CMH). Royal Canin Renal. Contrôle T4+créatinine+TA dans 4 semaines.') RETURNING id) INSERT INTO _cons_ids SELECT 173, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=173),'SEED-0174',320,20,384,'payée','2025-04-07','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=77), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-02-12','DM résistant à l''insuline — suspicion acromégalie','Chat Européen mâle castré 11 ans (Biscuit). DM insulino-dépendant depuis 18 mois. Nécessite doses croissantes d''insuline (actuellement 6 UI BID sans contrôle). Prise de poids paradoxale malgré DM.','Poids 7,2 kg (obèse). Traits faciaux élargis (prognatisme). IGF-1 sérique: 1850 ng/mL (N < 900 — très élevé). Glycémie 28 mmol/L. IRM hypophyse: microadénome hypophysaire GH-sécrétant 4mm.','Acromégalie féline (tumeur hypophysaire GH) — DM résistant secondaire. Traitement: radiothérapie stéréotaxique (référence centre spécialisé) ou hypophysectomie. Sans traitement: insuline progressive sans contrôle possible.','TERMINEE','Insuline glargine (Lantus) 1-2 UI BID (meilleure sur acromégalie que Caninsulin). IGF-1 contrôle 3 mois. Référence centre radiothérapie vétérinaire (ENVT, Alfort).') RETURNING id) INSERT INTO _cons_ids SELECT 174, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=174),'SEED-0175',650,20,780,'payée','2025-02-12','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=7), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-22','Ulcères muco-cutanés extensifs — pemphigus foliacé','Milou, WHWT mâle 7 ans, atopique. Après épisodes répétés pyodermite, apparition lésions insolites: pustules stériles non répondantes aux antibiotiques, croûtes épaisses face, oreilles, plantes. Aggravation rapide.','Croûtes jaunâtres épaisses perioccipitales, auriculaires, plantes des pieds et jonction muqueuse-peau. Pustules stériles. Pas de prurit. Culture: stérile. Cytologie pustule: acantholyse + neutrophiles sans bactéries. Biopsie cutanée: pemphigus foliacé confirmé.','Pemphigus foliacé — dermatose auto-immune la plus fréquente chez le chien. Traitement immunosuppresseur lourd. Pronostic variable. Distinguer de pyodermite (crucial — antibiotiques CI seuls).','TERMINEE','Prednisone 2 mg/kg/j SID induction (4 semaines). Azathioprine 2 mg/kg SID (épargnant stéroïdes — chien). Contrôle NFS J14 (myélosuppression azathioprine). Réduction progressive prednisone dès rémission.') RETURNING id) INSERT INTO _cons_ids SELECT 175, id FROM ins;
