WITH pi AS (SELECT id FROM _patient_ids WHERE idx=38), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-10-07','Pâleur soudaine — anémie hémolytique immune','Chien race mixte femelle 5 ans (Sasha2). Propriétaire: animal effondré ce matin, muqueuses très pâles, léthargique. Pas d''exposition toxique connue. Aucun médicament récent.','Muqueuses ictériques + pâles. FC 160/min. FR 55/min. Hématocrite 12% (critique). NFS: anémie régénérative macrocytaire, sphérocytes nombreux, auto-agglutination positive (test saline). Test de Coombs direct: fortement positif. Bilirubinémie 85 µmol/L.','AHMI (anémie hémolytique à médiation immune) — urgence transfusionnelle. Transfusion culot GR + immunosuppression lourde. Pronostic réservé (mortalité 30-70% premiers jours).','TERMINEE','Transfusion 10-15 mL/kg culot érythrocytaire (groupage DEA1 urgent). Prednisone 2 mg/kg/j IV. Azathioprine 2 mg/kg SID. Héparine 200 UI/kg SC TID (prévention CIVD). Oméprazole + sucralfate.') RETURNING id) INSERT INTO _cons_ids SELECT 176, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=176),'SEED-0177',795,20,954,'payée','2024-10-07','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=124), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-03','Polyarthrite fébrile — polyarthrite rhumatoïde','Chien Shetland mâle castré 7 ans (Pip). Boiteries multiples migratoires depuis 3 mois, touchant alternativement plusieurs articulations. Fièvre récurrente 39,5-40°C. Abattement épisodique.','Gonflement articulaire poignets bilatéraux + jarrets. Douleur à la mobilisation passive. T°39,8°C. NFS: leucocytose 18 G/L. Liquide synovial: >10000 leucocytes/µL (neutrophiles 85%) — sans bactéries. FR (Facteur Rhumatoïde): positif (titre 1:160). ANA positif.','Polyarthrite rhumatoïde séropositive (FR+). Maladie auto-immune érosive — pronostic articulaire réservé sans traitement précoce. Immunosuppression agressive.','TERMINEE','Prednisone 2 mg/kg/j induction. Azathioprine 2 mg/kg SID. Lévamisole discuté. Réévaluation articulaire J30. Radiographies articulaires bilatérales (érosions).') RETURNING id) INSERT INTO _cons_ids SELECT 177, id FROM ins;
