WITH pi AS (SELECT id FROM _patient_ids WHERE idx=162), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2024-11-15','Lésions cutanées + fièvre + arthralgies — LED suspecté','Chien Colley mâle 6 ans (Gringo, suivi dermato). Apparition nouvelles lésions: dépigmentation nasale, lésions ulcéreuses jonctions muco-cutanées, arthralgies, photosensibilité. Fièvre intermittente 40°C.','Dépigmentation nez (symétrique). Ulcères lèvres, jonction nasale. Protéinurie +++ (atteinte glomérulaire). ANA: positif titre 1:640. Anti-dsDNA positif. Complément C3 bas. Hématocrite 28% (anémie hémolytique légère).','Lupus érythémateux disséminé (LED) canin — forme systémique avec atteinte rénale (glomérulonéphrite lupique). Traitement immunosuppresseur + protection solaire. Pronostic selon atteinte rénale.','TERMINEE','Prednisone 2 mg/kg/j. Azathioprine 2 mg/kg SID. Benazepril 0,5 mg/kg SID (néphroprotection). Acides gras oméga-3 (néphroprotecteur). Éviter exposition solaire. Contrôle protéinurie J30.') RETURNING id) INSERT INTO _cons_ids SELECT 178, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=178),'SEED-0179',393,20,471.6,'payée','2024-11-15','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=26), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-10','Épilepsie réfractaire — Berger Belge','Sasha, Berger Belge 5 ans. Sous phénobarbital 3 mg/kg BID + bromure K depuis 6 mois. Propriétaire: crises groupées (cluster) hier — 3 crises en 4h malgré traitement. Statut épileptique évité de justesse.','Post-ictale. Phénobarbital: 32 µg/mL (thérapeutique). Bromure: 800 mg/L (sous-thérapeutique — cible 1000-2000). Pas d''anomalie neurologique inter-ictale. IRM: normale (épilepsie idiopathique).','Épilepsie réfractaire — crises groupées. Ajout 3ème antiépileptique: lévetiracétam. Augmentation dose bromure. Plan de sauvetage renforcé. Discussion statut épilepticus (diazépam IV si > 5 min).','TERMINEE','Lévetiracétam (Keppra) 20 mg/kg TID ajouté. Bromure augmenté: loading dose 400 mg/kg PO divisée 4 jours. Diazépam rectal 2 mg/kg renouvelé. Hospitalisation 24h post-cluster.') RETURNING id) INSERT INTO _cons_ids SELECT 179, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=179),'SEED-0180',660,20,792,'payée','2025-04-10','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=18), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-02-15','IVDD grade 5 — perte nociception — urgence','Cannelle, Teckel femelle 7 ans. Paraplégie traitée conservativement il y a 6 mois (grade 3). Après amélioration partielle, rechute brutale: paraplégie complète avec perte sensibilité profonde ce matin.','Paraplégie complète grade 5/5 IVDD. Nociception profonde: ABSENTE bilatérale. Tonus cloacal absent. IRM urgente: hernie discale massive L1-L2, écrasement moelle > 80%, signal syringomyélique suspect.','IVDD grade 5 — perte nociception profonde. Urgence neurochirurgicale absolue. Pronostic: < 50% récupération si chirurgie dans 24h, < 5% si > 48h. Chirurgie d''urgence dans 4h.','TERMINEE','Chirurgie d''urgence dans les 4 heures. Cage rest absolu. Analgésie: méthadone 0,4 mg/kg IV. Méthylprednisolone 30 mg/kg IV dose unique pré-op (controversé).') RETURNING id) INSERT INTO _cons_ids SELECT 180, id FROM ins;
