WITH pi AS (SELECT id FROM _patient_ids WHERE idx=29), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-20','Myélopathie dégénérative avancée — Malinois','Nemo, Malinois mâle 9 ans (suivi DM). Progression myélopathie: maintenant paraplégie quasi-complète, incontinence fécale et urinaire. Test génétique SOD1: homozygote (At/At) — myélopathie dégénérative confirmée.','Paraplégie fonctionnelle (quelques mouvements résiduels volontaires). Incontinence permanente. Proprioception absente. Atrophie musculaire sévère membres postérieurs. IRM: démyélinisation étendue moelle thoracolombaire.','Myélopathie dégénérative stade avancé. Pas de traitement curatif. Discussion qualité de vie avec propriétaire. Chariot de mobilité (wheelchair) proposé. Soins infirmiers intensifs. Euthanasie discutée si souffrance ou refus soins.','TERMINEE','Chariot de mobilité canin adapté (mesures prises). Physiothérapie 3x/semaine (maintien muscle antérieur). Nursing incontinence BID. Acides gras oméga-3. Réévaluation qualité de vie mensuelle.') RETURNING id) INSERT INTO _cons_ids SELECT 181, id FROM ins;
