WITH pi AS (SELECT id FROM _patient_ids WHERE idx=200), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-28','Ataxie aiguë + nystagmus — syndrome vestibulaire central','Eden, Golden Retriever femelle 9 ans (CMD B2 connue). Propriétaire: apparition brutale en 2h de tête penchée, yeux qui roulent, incapacité à marcher. Crises de vomissements.','Head tilt marqué à gauche. Nystagmus horizontal (phase rapide à droite). Ataxie sévère, chutes. Proprioception présente (syndrome central vs périphérique). Déficits CN: face gauche légère parésie. IRM cérébrale: lésion focale cervelet gauche (AVC cérébelleux? tumeur?).','Syndrome vestibulaire central — lésion cérébrale. Diagnostic différentiel: AVC ischémique cérébelleux (probable CMD) vs tumeur vs inflammation. Traitement: réduction oedème cérébral + traitement étiologique.','TERMINEE','Mannitol 1g/kg IV lent (oedème cérébral). Dexaméthasone 0,1 mg/kg SID (si tumeur/inflammatoire). Maropitant IV anti-émétique. Aspégic 5 mg/kg SID (si AVC ischémique sur CMD). IRM contrôle 1 mois.') RETURNING id) INSERT INTO _cons_ids SELECT 182, id FROM ins;
