WITH pi AS (SELECT id FROM _patient_ids WHERE idx=31), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-05-08','Lymphome stade IV — décision soins palliatifs','Axel, Boxeur 7 ans. Rechute précoce lymphome (cf. cas précédent). Propriétaire confirme choix soins palliatifs après discussion. Animal encore alerte mais anorexique et dyspnéique légèrement.','Lymphadénomégalie généralisée massive. Épanchement pleural gauche. Poids: -4 kg depuis diagnostic. Appétit quasi-nul. Hématocrite 22%. Qualité de vie score 3/10.','Lymphome stade IV — soins palliatifs acceptés. Plan: analgésie, appétit, bien-être, décision euthanasie si qualité vie < seuil acceptable. Accompagnement famille.','TERMINEE','Prednisone 40 mg/m2 SID (palliatif, améliore appétit). Chlorambucil 20 mg/m2 PO J1/J14. Mirtazapine 3,75 mg PO tous les 3 jours (orexigène). Buprenorphine 0,02 mg/kg SC TID. Discussion euthanasie préparée.') RETURNING id) INSERT INTO _cons_ids SELECT 183, id FROM ins;
