WITH pi AS (SELECT id FROM _patient_ids WHERE idx=33), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-01-09','Ostéosarcome — amputation membre + chimio adjuvante','Nino, chien grande taille 8 ans (ostéosarcome radius D diagnostiqué en novembre). Propriétaire a accepté amputation + carboplatine adjuvant après réflexion. Bilan extension: méta pulmonaires micronodulaires stables.','Douleur intense membre droit malgré analgésie multi-modale. Masse radius distal 10cm. Poids 35 kg. Bilan pré-op: normaux. TA normale. Groupage DEA1+.','Amputation membre antérieur droit + chemio carboplatine adjuvante x4 cycles. Pronostic: médiane survie 12-18 mois si réponse complète. Déambulation post-amputation: habituellement excellente chez chien.','TERMINEE','Amputation chirurgicale programmée. Carboplatine 300 mg/m2 IV J14 post-op puis toutes les 3 semaines x3. Physiothérapie tri-membre. Réévaluation thorax J90.') RETURNING id) INSERT INTO _cons_ids SELECT 184, id FROM ins;
