WITH pi AS (SELECT id FROM _patient_ids WHERE idx=91), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-25','Lymphome médiastinal — soins palliatifs décidés','Merlin, chat 5 ans, lymphome médiastinal sous COP (3 cycles). Rémission partielle initiale puis rechute J60. Propriétaire: décide soins palliatifs (refus chimio agressive suite aux effets secondaires).','Dyspnée modérée. Masse médiastinale toujours présente (plus large). Poids 3,1 kg (-600g). Score condition corporelle 3/9. Appétit variable.','Lymphome médiastinal félin rechute — soins palliatifs exclusifs. Objectif: qualité de vie, dyspnée contrôlée, alimentation maintenue. Accompagnement propriétaire pour fin de vie.','TERMINEE','Prednisone 2 mg/kg SID (anti-inflammatoire + anti-tumoral palliatif). Mirtazapine 1,88 mg PO tous les 3j (orexigène). Buprenorphine transdermique si dyspnée. Thoracocentèse palliative si besoin.') RETURNING id) INSERT INTO _cons_ids SELECT 185, id FROM ins;
