WITH pi AS (SELECT id FROM _patient_ids WHERE idx=128), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-30','Carcinome squameux stade IV — soins fin de vie','Obi, Persan 11 ans. Carcinome épidermoïde buccal diagnostiqué en mars (cas precedent). Evolution défavorable: tumeur étendue, anorexie totale, douleur intense malgré analgésie. Perte de poids 1,2 kg en 6 semaines.','Score douleur 8/10 (grimace féline). Anorexie totale. Muqueuses buccales nécrotiques. Ptyalisme hémorragique. Score qualité de vie 2/10.','Carcinome squameux stade IV — fin de vie. Discussion euthanasie avec propriétaire. Décision acceptée. Euthanasie programmée 48h après pour permettre famille de faire leurs adieux.','TERMINEE','Buprenorphine 0,03 mg/kg SC TID (analgésie maximale). Euthanasie dans 48h. Accompagnement famille, explication protocole euthanasie.') RETURNING id) INSERT INTO _cons_ids SELECT 186, id FROM ins;
