WITH pi AS (SELECT id FROM _patient_ids WHERE idx=52), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-20','AVP sévère — polytraumatisme chien','Mango, Labrador 3 ans (déjà opéré fracture radius AVP en 2024). Nouvel AVP — choc violent voiture. Multiple blessures apparent. Amené immédiatement.','État de choc sévère: TA 55/35, FC 180/min, muqueuses blanches TRC 4s. FAST abdominal: épanchement péri-hépatique. Pneumothorax droit (épanchement gazeux). Côtes 5-7 fracturées D. Plaie ouverte crâne 8 cm. Fracture fémur G.','Polytraumatisme sévère: choc hémorragique + pneumothorax + fractures multiples + plaie crânienne. Priorité ABC. Thoracocentèse urgente + réanimation + chirurgie dans les 2h.','TERMINEE','Protocole damage control: NaCl 7,5% hypertonique 4 mL/kg IV + HEA 10 mL/kg. Thoracocentèse droit urgente (air). Oxygène FiO2 100%. Chirurgie laparotomie + ostéosynthèse dans 2h.') RETURNING id) INSERT INTO _cons_ids SELECT 187, id FROM ins;
