WITH pi AS (SELECT id FROM _patient_ids WHERE idx=141), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-04-05','Chute hauteur + pneumothorax + multi-fractures — chat','Chat européen femelle 3 ans (déjà opérée fracture fémur chute 4ème étage en 2024). Nouvelle chute 5ème étage. Propriétaire: amène en urgence, chat respire avec effort.','Détresse respiratoire: FR 65/min, muqueuses cyanosées. Auscultation: silence hémithorax gauche. Pneumothorax G massif + hémothorax. Mandibule fracturée (fracture symphyse). Pelvienne: bassin asymétrique (fracture ilion). TA 70/40.','Syndrome de chute sévère — 2ème épisode. Thoracocentèse G en urgence (priorité respiratoire). Stabilisation hémodynamique. Chirurgie mandibule + pelvis dans 48h.','TERMINEE','Thoracocentèse G urgente. NaCl 0,9% réanimation. O2 FiO2 100%. Morphine IV 0,3 mg/kg. Chirurgie mandibule + pelvis dans 48h après stabilisation.') RETURNING id) INSERT INTO _cons_ids SELECT 188, id FROM ins;
