WITH pi AS (SELECT id FROM _patient_ids WHERE idx=175), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-28','AVP + hémorragie interne — Berger Australien','Faro, Berger Australien 4 ans (déjà vu CE intestinal). Renversé par voiture à faible vitesse. Apparemment indemne initialement puis collapsus à domicile 2h après.','Choc hémorragique: TA 60/35, FC 170/min, pâleur. FAST abdominal: large épanchement abdominal anéchogène. Hématocrite 18% (chute rapide). Splénomégalie + masse hépatique suspecte. Hémopéritoine massif.','Hémopéritoine post-traumatique sur probable rupture rate ou lésion hépatique. Choc hémorragique. Chirurgie urgente (splénectomie). Réanimation parallèle.','TERMINEE','NaCl 7,5% 4 mL/kg IV + plasmalyte. Transfusion 10 mL/kg culot GR en urgence. Chirurgie laparotomie dans 1h.') RETURNING id) INSERT INTO _cons_ids SELECT 189, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=189),'SEED-0190',1230,20,1476,'payée','2025-03-28','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=38), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-15','Hémorragies spontanées — thrombocytopénie immune','Sasha2, chien 5 ans (AHMI traitée en 2024). Apparition pétéchies et ecchymoses diffuses sur abdomen. Epistaxis bilatérale. Pas de trauma.','Pétéchies et ecchymoses ventrales diffuses. Epistaxis bilatérale active. Hématocrite 32% (légère). Plaquettes: 8 000/µL (critique — N: >200 000). Temps saignement prolongé. Anti-plaquettaires: positifs (TPAI).','Thrombocytopénie immune primaire (TPI / ITP) — possible rechute syndrome auto-immun chez cette chienne. Traitement identique AHMI: prednisone + azathioprine + IVIG si disponible.','TERMINEE','Prednisone 2 mg/kg/j SID. Azathioprine 2 mg/kg SID. Doxycycline 10 mg/kg BID 30j (rickettsie à exclure). Restriction activité absolue. Hospitalisation si plaquettes < 5000. Contrôle NFS J5.') RETURNING id) INSERT INTO _cons_ids SELECT 190, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=190),'SEED-0191',430,20,516,'payée','2025-04-15','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=77), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-04-22','Dyspnée + écho anormale — cardiomyopathie restrictive féline','Biscuit, chat 11 ans (acromégalie). Dyspnée modérée. Échocardiographie de contrôle réalisée. Résultat inattendu: image atypique suggérant cardiomyopathie restrictive (rare).','FR 42/min. Auscultation: galop. Echo: cavité VG non dilatée, épaississement modéré, mais surtout fusion feuillets mitral + oblitération VG partielle en systole (pattern restrictif). RVSP élevé. Thrombus intra-auriculaire suspecté (AG +).','Cardiomyopathie restrictive féline (RCMP) — forme rare chez le chat, pronostic sombre (médiane 3-9 mois). Complication: thrombus intra-atriale. Traitement anti-thrombotique + diurétiques. Gestion complexe.','TERMINEE','Furosémide 1 mg/kg BID (insuffisance cardiaque). Clopidogrel 18,75 mg SID (thrombus). Warfarine 0,05 mg/kg SID + monitoring INR (si thrombus confirmé). Atenolol 6,25 mg SID. Pronostic discuté propriétaire.') RETURNING id) INSERT INTO _cons_ids SELECT 191, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=191),'SEED-0192',510,20,612,'payée','2025-04-22','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=124), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-03-15','Épistaxis + ecchymoses — maladie de von Willebrand','Pip, Shetland 7 ans (polyarthrite traitée). Chirurgie arthroscopique programmée pour bilan articulaire — annulée car saignement excessif à la ponction synoviale. Bilan coagulation demandé.','Epistaxis spontanée légère. Ecchymose site ponction persistante. TP: normal. TTPA: normal. FvW:Ag: 12% (N > 50%) — très bas. Génotypage: hétérozygote vWD type I. Temps de saignement cutané: 14 min (N < 5 min).','Maladie de von Willebrand type I modérée — Shetland prédisposé. Gestion: DDAVP (desmopressine) pré-chirurgical + plasma frais congelé. Chirurgie arthroscopique reprogrammée avec protocole hémostatique.','TERMINEE','DDAVP (desmopressine) 1 µg/kg SC 30 min avant toute chirurgie. Plasma frais congelé disponible en salle d''op. Contre-indication: aspirine, AINS, héparine. Carte patient à remettre au propriétaire.') RETURNING id) INSERT INTO _cons_ids SELECT 192, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=192),'SEED-0193',295,20,354,'payée','2025-03-15','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=155), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-05-05','Épanchements récidivants — PIF suspecté','Nox, chat européen 5 ans (Addison traité). Depuis 6 semaines, épanchement pleural récidivant traité 3 fois par thoracocentèse. Appétit variable, légère fièvre. PCR FCoV positif.','Fièvre 40,1°C. Épanchement pleural bilatéral réaccumulé (500 mL drainés). Liquide jaune doré, visqueux, protéines > 45 g/L, Rivalta positif. AGP sérique élevée. PCR FCoV ARN dans le liquide: positif fortement (PIF forme humide).','PIF forme humide (péritonite infectieuse féline) — diagnostic quasi-certain. Traitement: GS-441524 (antiviral oral, remoquavir, ou molnupiravia générique PIF). Pronostic drastiquement amélioré avec antiviraux (>80% rémission).','TERMINEE','GS-441524 6 mg/kg SID SC (ou équivalent oral disponible) pendant 12 semaines minimum. Monitoring bilan hépatique + protéines toutes 2 semaines. Pronostic bon si traitement initié précocement. Information propriétaire sur coût traitement.') RETURNING id) INSERT INTO _cons_ids SELECT 193, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=193),'SEED-0194',545,20,654,'payée','2025-05-05','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=145), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Sophie Laurent','vet_clerk_003','2025-03-30','HTA sévère + hypokaliémie — hyperaldostéronisme félin','Bijou, Yorkshire 2 ans (suivi shunt porto-systémique). Chat différent — patient 145 second animal du foyer: Européen mâle castré 10 ans. HTA découverte lors bilan annuel: TA 195/130 mmHg. Hypokaliémie 2,8 mmol/L.','TA Doppler 195/130 mmHg sur 3 mesures. Faiblesse musculaire membre postérieur gauche (hypokaliémie). K+ 2,8 mmol/L. Aldostérone sérique: 1850 pmol/L (N < 500). Écho surrénales: masse surrénale droite 1,2 cm (adénome aldostérone).','Hyperaldostéronisme primaire félin (syndrome de Conn) sur adénome surrénalien. Rare mais sous-diagnostiqué. Traitement médical (spironolactone) vs chirurgie (surrénalectomie). Choix médical retenu (comorbidités).','TERMINEE','Spironolactone 2 mg/kg SID (anti-aldostérone). Amlodipine 0,625 mg SID (HTA). Gluconate de potassium 2 mEq/kg SID PO. Contrôle TA + K+ J14. Objectif TA < 160 mmHg.') RETURNING id) INSERT INTO _cons_ids SELECT 194, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=194),'SEED-0195',350,20,420,'payée','2025-03-30','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=3), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2024-11-05','Suivi post-GDV J7 — complications arythmies','Brutus, Dogue Allemand 5 ans. GDV opéré il y a 7 jours (cas precedent). Sorti J3 post-op. Propriétaire rappelle: épisodes de faiblesse, syncope courte ce matin.','ECG: extrasystoles ventriculaires multifocales, salves de TV non soutenue. FC 90/min. TA: 100/70. Hématocrite 32%. Troponine I: 3,8 ng/mL (élevée — nécrose myocardique post-GDV).','Arythmies ventriculaires post-GDV — fréquentes à J5-J10 (lésion de reperfusion myocardique). Traitement anti-arythmique si TV soutenue. Monitoring ambulatoire Holter 24h. Pronostic cardiaque généralement bon à long terme.','TERMINEE','Sotalol 2 mg/kg BID PO (anti-arythmique si TV persistante). Holter ECG 24h (capture arythmies). Restriction activité 4 semaines. Contrôle troponine + ECG J14.') RETURNING id) INSERT INTO _cons_ids SELECT 195, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=195),'SEED-0196',245,20,294,'payée','2024-11-05','virement');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=56), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2025-04-03','Boiterie chronique — Berger Australien — suivi arthrose bilatérale','Quartz, Berger Australien mâle 9 ans. Bilan semestriel arthrose hanche et coudes bilatérale. Propriétaire: mobilité dégradée malgré Méloxicam, difficultés à monter les escaliers.','Score douleur 5/10 CBPS. Mobilité réduite hanches bilatérale (coxofémoral). Muscles fessiers atrophiés. Radio: coxarthrose grade 3 bilatérale, remaniements coudes grade 2. Poids 29 kg (stable).','Arthrose avancée — escalade thérapeutique justifiée. Ajout gabapentine + PRP (plasma riche en plaquettes) intra-articulaire hanche ou référence rhumatologie pour prothèse totale hanche (PTH). Kinésithérapie aquatique optimisée.','TERMINEE','Gabapentine 10 mg/kg BID ajoutée. Méloxicam 0,1 mg/kg SID maintenu. Physiothérapie aquatique 3x/semaine. Acides gras oméga-3 haute dose. Injection PRP hanche droite programmée. Référence chirurgie PTH discutée.') RETURNING id) INSERT INTO _cons_ids SELECT 196, id FROM ins;
INSERT INTO factures (clinic_id, consultation_id, numero, montant_ht, tva, montant_ttc, statut, date_emission, mode_paiement) VALUES ('clinic_seed_demo',(SELECT id FROM _cons_ids WHERE idx=196),'SEED-0197',435,20,522,'payée','2025-04-03','CB');
WITH pi AS (SELECT id FROM _patient_ids WHERE idx=186), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Marie Dubois','vet_clerk_001','2025-02-20','Vaccinations — chaton Exotic Shorthair 3 mois','Sushi, Exotic Shorthair mâle 3 mois. Premier contact avec un vétérinaire. Propriétaire nouveau avec chats. Questions sur vaccination, antiparasitaire, alimentation. Animal acquis chez éleveur (carnet vaccinal vierge).','Excellent état général. Poids 900g. T°38,7°C. Auscultation normale. Pas de parasites visibles. Pas de décharge nasale ou oculaire. Hernie ombilicale minime (à surveiller).','1ère injection TCRCh primo (Typhus-Coryza-Rage-Chlamydophila). Programme complet: rappel J28, puis annuel. Antiparasitaire adapté âge.','TERMINEE','Antiparasitaire interne: Milbemax chat 0,5-2 kg 1/2 comprimé. Antiparasitaire externe: Frontline spray. Alimentation Royal Canin Kitten jusqu''à 12 mois. Stérilisation recommandée à 5-6 mois.') RETURNING id) INSERT INTO _cons_ids SELECT 197, id FROM ins;
