WITH pi AS (SELECT id FROM _patient_ids WHERE idx=213), ins AS (INSERT INTO consultations (clinic_id, patient_id, veterinaire, veterinaire_id, date, motif, anamnese, examen_clinique, notes, statut, ordonnance) VALUES ('clinic_seed_demo',(SELECT id FROM pi),'Dr. Thomas Renard','vet_clerk_002','2025-03-10','Traumatisme crânien — chaton chute table','Chaton Siamois mâle 4 mois (Ciel). Chute de la table de nuit (~80 cm). Prostration immédiate post-chute, conscient mais hébété. Propriétaire très angoissé.','Score Glasgow félin: 14/18 (légèrement altéré). Pupilles isocoriques, réactives. Pas de trouble posture. FR 30/min. T°37,8°C. Pas de plaie externe crânienne. Bilan ophtalmologique normal. Radio crâne: pas de fracture visible.','Traumatisme crânien léger (score Glasgow modifié 14/18). Observation en clinic 4h. Pas de signe de hypertension intracrânienne (vomissements, anisocorie, décrochage conscience). Pronostic excellent.','TERMINEE','Observation en clinique 4h. Mannitol en STANDBY (non administré — pas d''HIC). Retour à domicile si stable. Consignes: urgence si vomissements répétés, désorientation, anisocorie. Pas d''AINS 24h (risque vasculaire cérébral).') RETURNING id) INSERT INTO _cons_ids SELECT 198, id FROM ins;
